.cs1_lock_green a {
	background: url(//upload.wikimedia.org/wikipedia/commons/thumb/6/65/Lock-green.svg/9px-Lock-green.svg.png) no-repeat right;
	}

.cs1_lock_blue a {
	background: url(//upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Lock-blue-alt-2.svg/9px-Lock-blue-alt-2.svg.png) no-repeat right;
	}

.cs1_lock_red a {
	background: url(//upload.wikimedia.org/wikipedia/commons/thumb/c/c8/Lock-red-alt.svg/9px-Lock-red-alt.svg.png) no-repeat right;
	}

.cs1_lock_green a {
	background: url(//upload.wikimedia.org/wikipedia/commons/thumb/6/65/Lock-green.svg/9px-Lock-green.svg.png) no-repeat;
	background-position: right .2em center;
	}

.cs1_lock_blue a {
	background: url(//upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Lock-blue-alt-2.svg/9px-Lock-blue-alt-2.svg.png) no-repeat;
	background-position: right .2em center;
	}

